  background: #ecf8f1;
}

#resultsBody tr.scan-row-done.scan-row-latest td {
  background: #e4f5ec !important;
  box-shadow: inset 4px 0 0 var(--success-ink);
}

.row-scan-progress {
  display: block;
  margin-top: 3px;
  font-size: 11px;
  line-height: 1.2;
  color: #708196;
  font-weight: 650;
}

tr.scan-row-done .row-scan-progress {
  color: var(--success-ink);
}

