operations.new:
function renderRowTable(rows) {
  resultsBody.innerHTML = rows.map((row) => {
    const ean = getSkuDisplayEan(row.sku);
    const required = scanState.requirements.get(row.sku) || 0;
    const scanned = scanState.scannedCounts.get(row.sku) || 0;
    const hasProgress = Boolean(scanState.activePalletId && required > 0);
    const cappedScanned = Math.min(scanned, required);
    const rowClasses = [];

    if (hasProgress && cappedScanned > 0) {
      rowClasses.push("scan-row-progress");
    }
    if (hasProgress && cappedScanned >= required) {
      rowClasses.push("scan-row-done");
    }
    if (hasProgress && scanState.lastScannedSku === row.sku) {
      rowClasses.push("scan-row-latest");
    }

    const progressText = hasProgress
      ? '<span class="row-scan-progress">' + cappedScanned + ' / ' + required + ' scanned</span>'
      : "";

    return (
      '<tr class="' + rowClasses.join(" ") + '">' +
        '<td class="mono">' + escapeHtml(row.sku || "-") + "</td>" +
        '<td class="mono">' + escapeHtml(ean) + "</td>" +
        '<td class="mono">' + escapeHtml(row.qty || "-") + progressText + "</td>" +
        '<td class="mono">' + escapeHtml(row.palletId || "-") + "</td>" +
        '<td class="mono">' + escapeHtml(row.containerId || "-") + "</td>" +
      "</tr>"
    );
  }).join("");
}

operations.old:
skuChipList.innerHTML = [...scanState.requirements.entries()].map(([sku, required]) => {
  const scanned = scanState.scannedCounts.get(sku) || 0;
  const doneClass = scanned >= required ? " done" : "";
  const ean = getSkuDisplayEan(sku);
  return '<div class="sku-chip' + doneClass + ' mono">' +
    escapeHtml(sku) +
    '<span class="sub">EAN: ' + escapeHtml(ean) + ' | ' + scanned + " / " + required + "</span>" +
    "</div>";
}).join("");
